import React, { useState } from 'react';
import SignUp from './SignUp';
import SignIn from './SignIn';

function App() {
  const [token, setToken] = useState(null);
  const [isSignUp, setIsSignUp] = useState(false); // Toggle between SignIn and SignUp

  return (
    <div style={{ fontFamily: 'Arial, sans-serif', maxWidth: '400px', margin: 'auto', padding: '20px' }}>
      <h1 style={{ textAlign: 'center', color: '#333' }}>Sports Stats App</h1>
      {!token ? (
        <div style={{ backgroundColor: '#f9f9f9', padding: '20px', borderRadius: '10px', boxShadow: '0 2px 5px rgba(0, 0, 0, 0.1)' }}>
          {isSignUp ? (
            <SignUp />
          ) : (
            <SignIn setToken={setToken} />
          )}
          <p style={{ textAlign: 'center', marginTop: '10px' }}>
            {isSignUp ? (
              <span>
                Already have an account?{' '}
                <button onClick={() => setIsSignUp(false)} style={subscriptButtonStyle}>
                  Sign In
                </button>
              </span>
            ) : (
              <span>
                Don't have an account?{' '}
                <button onClick={() => setIsSignUp(true)} style={subscriptButtonStyle}>
                  Sign Up
                </button>
              </span>
            )}
          </p>
        </div>
      ) : (
        <div>Welcome! You are logged in with a token: {token}</div>
      )}
    </div>
  );
}

const subscriptButtonStyle = {
  border: 'none',
  background: 'none',
  color: '#007BFF',
  cursor: 'pointer',
  textDecoration: 'underline',
  fontSize: '0.9em',
};

export default App;
